def gen(rng, size):
    letters = 'abcdefghijklmnopqrstuvwxyz'
    n = max(1, min(size, 100))
    words = []
    for _ in range(n):
        wlen = rng.randint(1, 10)
        words.append(''.join(rng.choice(letters) for _ in range(wlen)))
    if rng.random() < 0.5:
        s = ''.join(w[0] for w in words)
    else:
        slen = rng.randint(1, 100)
        s = ''.join(rng.choice(letters) for _ in range(slen))
    return [words, s]

